import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
import reportWebVitals from './reportWebVitals';

class Calculator extends React.Component{

  constructor(props){

    super(props);

    this.state = {result:""};

  }

  enterKey = (e) =>{

    this.setState({result: this.state.result + e.target.name});

  }

  backspace = () =>{

    this.setState({result: this.state.result.slice(0, this.state.result.length-1)});

  }

  clear = () =>{

    this.setState({result: ""});

  }

  sum = () =>{

    this.setState({result: eval(this.state.result)});

  }


  render(){

    return(

      <div id="container">

        <div id="inputOutput">{this.state.result}</div>

        <div id="keyPad">

          <button name="(" onClick={this.enterKey}>(</button>
          <button name="CE" onClick={this.backspace}>CE</button>
          <button name=")" onClick={this.enterKey}>)</button>
          <button name="C" onClick={this.clear}>C</button>

          <button name="1" onClick={this.enterKey}>1</button>
          <button name="2" onClick={this.enterKey}>2</button>
          <button name="3" onClick={this.enterKey}>3</button>
          <button name="+" onClick={this.enterKey}>+</button>

          <button name="4" onClick={this.enterKey}>4</button>
          <button name="5" onClick={this.enterKey}>5</button>
          <button name="6" onClick={this.enterKey}>6</button>
          <button name="-" onClick={this.enterKey}>-</button>

          <button name="7" onClick={this.enterKey}>7</button>
          <button name="8" onClick={this.enterKey}>8</button>
          <button name="9" onClick={this.enterKey}>9</button>
          <button name="*" onClick={this.enterKey}>x</button>

          <button name="." onClick={this.enterKey}>.</button>
          <button name="=" onClick={this.sum}>=</button>
          <button name="0" onClick={this.enterKey}>0</button>
          <button name="/" onClick={this.enterKey}>/</button>

          

        </div>

      </div>


    );

  }

}

ReactDOM.render(<Calculator></Calculator>, document.getElementById('root'));


reportWebVitals();
